/**
 * Audio utilities for timer sounds
 */

// Simple beep for timer start
const TIMER_START_SOUND = 'data:audio/wav;base64,';

// Bell sound for timer completion
const TIMER_COMPLETE_SOUND = 'data:audio/wav;base64,';

/**
 * קלאס לניהול השמעת צלילים בממשק
 */
class AudioManager {
  private audioContext: AudioContext | null = null;
  private startBuffer: AudioBuffer | null = null;
  private completeBuffer: AudioBuffer | null = null;
  private initialized: boolean = false;
  private initializationPromise: Promise<void> | null = null;

  constructor() {
    // הרישום לאירועי משתמש לצורך אתחול מערכת השמע
    document.addEventListener('click', () => this.initialize(), { once: true });
    document.addEventListener('keydown', () => this.initialize(), { once: true });
  }

  /**
   * אתחול מערכת השמע - חייב להתבצע אחרי אינטראקציה של המשתמש
   */
  private initialize(): Promise<void> {
    if (this.initialized) {
      return Promise.resolve();
    }

    if (this.initializationPromise) {
      return this.initializationPromise;
    }

    this.initializationPromise = new Promise<void>((resolve) => {
      try {
        // יצירת אודיו קונטקסט חדש
        this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
        
        // טעינת הצלילים לתוך באפרים
        this.loadSound(TIMER_START_SOUND)
          .then(buffer => {
            this.startBuffer = buffer;
            return this.loadSound(TIMER_COMPLETE_SOUND);
          })
          .then(buffer => {
            this.completeBuffer = buffer;
            this.initialized = true;
            console.log("Audio system initialized successfully");
            resolve();
          })
          .catch(err => {
            console.error("Failed to load sounds:", err);
            resolve(); // נמשיך למרות השגיאה
          });
      } catch (error) {
        console.error("Error initializing audio system:", error);
        resolve(); // נמשיך למרות השגיאה
      }
    });

    return this.initializationPromise;
  }

  /**
   * טעינת צליל מ-base64 לתוך AudioBuffer
   */
  private loadSound(base64Sound: string): Promise<AudioBuffer> {
    return new Promise((resolve, reject) => {
      if (!this.audioContext) {
        reject(new Error("AudioContext not initialized"));
        return;
      }

      try {
        // המרת ה-base64 לאריי באפר
        const byteString = atob(base64Sound.split(',')[1]);
        const arrayBuffer = new ArrayBuffer(byteString.length);
        const intArray = new Uint8Array(arrayBuffer);
        
        for (let i = 0; i < byteString.length; i++) {
          intArray[i] = byteString.charCodeAt(i);
        }
        
        // פענוח הפורמט לאודיו באפר
        this.audioContext.decodeAudioData(
          arrayBuffer,
          (buffer) => resolve(buffer),
          (err) => reject(err)
        );
      } catch (error) {
        reject(error);
      }
    });
  }

  /**
   * השמעת צליל מתוך באפר
   */
  private playBuffer(buffer: AudioBuffer | null) {
    if (!this.audioContext || !buffer) {
      console.log("Cannot play sound: AudioContext or buffer not initialized");
      return;
    }
    
    try {
      // יצירת מקור שמע חדש והגדרת עוצמת קול
      const source = this.audioContext.createBufferSource();
      const gainNode = this.audioContext.createGain();
      
      source.buffer = buffer;
      
      // הגדרת עוצמת קול נמוכה יותר לצליל נעים יותר
      gainNode.gain.value = 0.4;
      
      // חיבור המקור לעוצמת קול ואז לרמקולים
      source.connect(gainNode);
      gainNode.connect(this.audioContext.destination);
      
      // הפעלת הצליל
      source.start(0);
    } catch (error) {
      console.error("Error playing sound:", error);
    }
  }

  /**
   * השמעת צליל התחלת טיימר
   */
  playTimerStart() {
    this.initialize().then(() => {
      this.playBuffer(this.startBuffer);
    });
  }

  /**
   * השמעת צליל סיום טיימר
   */
  playTimerComplete() {
    this.initialize().then(() => {
      this.playBuffer(this.completeBuffer);
    });
  }
}

// ייצוא של מופע יחיד לשימוש בכל הקומפוננטות
export const audioManager = new AudioManager();